#!/usr/bin/env node
/**
 * Regenerate modern/js/math-ai-cores-engine.js — single Math AI CAS engine bundle.
 *
 * Edit individual *-core.js sources, then:
 *   node scripts/build-math-ai-cores-bundle.mjs
 *
 * Output is minified (terser). Set MATH_AI_CORES_SKIP_MINIFY=1 for readable debug output.
 */
import fs from 'node:fs';
import path from 'node:path';
import os from 'node:os';
import { spawnSync } from 'node:child_process';
import { fileURLToPath } from 'node:url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const ROOT = path.join(__dirname, '..');
const WEBAPP = path.join(ROOT, 'src/main/webapp');
const MANIFEST = path.join(__dirname, 'math-ai-cores.manifest.json');
const SKIP_MINIFY = process.env.MATH_AI_CORES_SKIP_MINIFY === '1';

const manifest = JSON.parse(fs.readFileSync(MANIFEST, 'utf8'));
const files = manifest.files || [];
const OUT = path.join(WEBAPP, manifest.output || 'modern/js/math-ai-cores-engine.js');

function ensureNerdamerVendor() {
  const vendorRel = manifest.nerdamerVendorDir || 'js/vendor/nerdamer';
  const vendorDir = path.join(WEBAPP, vendorRel);
  const srcDir = path.join(ROOT, manifest.nerdamerSourceDir || 'system-equations-test/node_modules/nerdamer');
  const nerdFiles = manifest.nerdamerFiles || ['nerdamer.core.js', 'Algebra.js', 'Calculus.js', 'Solve.js'];

  if (!fs.existsSync(srcDir)) {
    console.error(`ERROR: nerdamer source missing at ${srcDir}`);
    console.error('  Run npm install in system-equations-test/ or set nerdamerSourceDir in manifest.');
    process.exit(1);
  }

  fs.mkdirSync(vendorDir, { recursive: true });
  for (const name of nerdFiles) {
    const from = path.join(srcDir, name);
    const to = path.join(vendorDir, name);
    if (!fs.existsSync(from)) {
      console.error(`ERROR: missing nerdamer file: ${from}`);
      process.exit(1);
    }
    if (!fs.existsSync(to) || fs.statSync(from).mtimeMs > fs.statSync(to).mtimeMs) {
      fs.copyFileSync(from, to);
      console.log(`  copied nerdamer → ${vendorRel}/${name}`);
    }
  }
}

function minifyWithTerser(code) {
  const tmpIn = path.join(os.tmpdir(), `math-ai-cores-build-${process.pid}.js`);
  const tmpOut = path.join(os.tmpdir(), `math-ai-cores-build-${process.pid}.min.js`);
  fs.writeFileSync(tmpIn, code);

  const terserBin = path.join(ROOT, 'scripts', 'node_modules', '.bin', 'terser');
  const cmd = fs.existsSync(terserBin) ? terserBin : 'npx';
  const args = fs.existsSync(terserBin)
    ? [tmpIn, '-c', 'passes=2', '--no-mangle', '--comments', '/^!|Generated by|math-ai-cores-engine/', '-o', tmpOut]
    : ['--yes', 'terser', tmpIn, '-c', 'passes=2', '--no-mangle', '--comments', '/^!|Generated by|math-ai-cores-engine/', '-o', tmpOut];

  const result = spawnSync(cmd, args, { cwd: ROOT, encoding: 'utf8' });

  try {
    fs.unlinkSync(tmpIn);
  } catch (_) {}

  if (result.status !== 0) {
    console.warn('  terser minify failed — writing unminified bundle');
    if (result.stderr) console.warn(result.stderr.trim());
    return { code, minified: false };
  }

  const minified = fs.readFileSync(tmpOut, 'utf8');
  try {
    fs.unlinkSync(tmpOut);
  } catch (_) {}
  return { code: minified, minified: true };
}

ensureNerdamerVendor();

const banner = `/* math-ai-cores-engine.js — unified Math AI CAS engine (single load)
   Generated by scripts/build-math-ai-cores-bundle.mjs on ${new Date().toISOString()}
   DO NOT EDIT BY HAND — edit sources in scripts/math-ai-cores.manifest.json, then rebuild.
   Modules (${files.length}): see manifest. */\n`;

let body = '';
let sourcesBytes = 0;
for (let i = 0; i < files.length; i++) {
  const rel = files[i];
  const abs = path.join(WEBAPP, rel);
  if (!fs.existsSync(abs)) {
    console.error(`ERROR: missing source: ${rel}`);
    process.exit(1);
  }
  const chunk = fs.readFileSync(abs, 'utf8');
  sourcesBytes += Buffer.byteLength(chunk, 'utf8');
  if (!SKIP_MINIFY) {
    body += chunk + '\n';
  } else {
    body += `\n\n/* === [${i + 1}/${files.length}] ${rel} === */\n${chunk}`;
  }
}

body += `\nwindow.__MATH_AI_CORES_LOADED__=true;\n`;

let out = SKIP_MINIFY
  ? `/* DEBUG (unminified) — set MATH_AI_CORES_SKIP_MINIFY=0 to minify */\n${banner}${body}`
  : banner + body;

const rawBytes = Buffer.byteLength(out, 'utf8');
let actuallyMinified = false;
if (!SKIP_MINIFY) {
  const result = minifyWithTerser(out);
  out = result.code;
  actuallyMinified = result.minified;
}

fs.writeFileSync(OUT, out);
const bundleBytes = fs.statSync(OUT).size;
const modeLabel = SKIP_MINIFY ? 'unminified (debug)' : (actuallyMinified ? 'minified' : 'unminified (terser failed)');
console.log(`✓ wrote ${OUT}`);
console.log(`  engine: ${bundleBytes} bytes  (concat: ${rawBytes} bytes, sources: ${sourcesBytes} bytes) [${modeLabel}]`);

// Remove legacy bundle filename if present
const legacy = path.join(WEBAPP, 'modern/js/math-ai-cores.bundle.js');
if (fs.existsSync(legacy)) {
  fs.unlinkSync(legacy);
  console.log('  removed legacy math-ai-cores.bundle.js');
}
